class MinHeap:
    def __init__(self, items=None):
        self.heap = []
        if items:
            self._build_heap(items)

    def _parent_idx(self, i):
        return (i - 1) // 2

    def _left_child_idx(self, i):
        return 2 * i + 1

    def _right_child_idx(self, i):
        return 2 * i + 2

    def _has_parent(self, i):
        return self._parent_idx(i) >= 0

    def _has_left_child(self, i):
        return self._left_child_idx(i) < len(self.heap)

    def _has_right_child(self, i):
        return self._right_child_idx(i) < len(self.heap)

    def _parent(self, i):
        return self.heap[self._parent_idx(i)]

    def _left_child(self, i):
        return self.heap[self._left_child_idx(i)]

    def _right_child(self, i):
        return self.heap[self._right_child_idx(i)]

    def _swap(self, i, j):
        self.heap[i], self.heap[j] = self.heap[j], self.heap[i]

    def _heapify_up(self, index):
        while self._has_parent(index) and self._parent(index) > self.heap[index]:
            self._swap(index, self._parent_idx(index))
            index = self._parent_idx(index)

    def _heapify_down(self, index):
        while self._has_left_child(index):
            smaller_child_idx = self._left_child_idx(index)
            if self._has_right_child(index) and self._right_child(index) < self._left_child(index):
                smaller_child_idx = self._right_child_idx(index)

            if self.heap[index] < self.heap[smaller_child_idx]:
                break
            else:
                self._swap(index, smaller_child_idx)
            index = smaller_child_idx

    def _build_heap(self, items):
        self.heap = list(items)
        n = len(self.heap)
        for i in range(n // 2 - 1, -1, -1):
            self._heapify_down(i)

    def peek(self):
        if self.is_empty():
            raise IndexError("Heap is empty")
        return self.heap[0]

    def insert(self, item):
        self.heap.append(item)
        self._heapify_up(len(self.heap) - 1)

    def extract_min(self):
        if self.is_empty():
            raise IndexError("Heap is empty")
        if len(self.heap) == 1:
            return self.heap.pop()

        min_item = self.heap[0]
        self.heap[0] = self.heap.pop()
        self._heapify_down(0)
        return min_item

    def is_empty(self):
        return len(self.heap) == 0

    def size(self):
        return len(self.heap)
